3_real_world_example.code:
console.log('1. Sync');

setTimeout(() => {
  console.log('5. Macro A');
  Promise.resolve().then(() => console.log('6. Micro C (inside Macro A)'));
}, 0);

Promise.resolve().then(() => {
  console.log('3. Micro A');
  setTimeout(() => console.log('7. Macro C (inside Micro A)'), 0);
});

setTimeout(() => {
  console.log('8. Macro B');
}, 0);

Promise.resolve().then(() => console.log('4. Micro B'));

console.log('2. Sync');

// Execution Order Trace:
// 1. Sync
// 2. Sync
// --- Call Stack Empty, process Microtasks ---
// 3. Micro A
// 4. Micro B
// --- Microtasks Empty, process ONE Macrotask ---
// 5. Macro A
// --- Macrotask finished, process Microtasks ---
// 6. Micro C (inside Macro A)
// --- Microtasks Empty, process next Macrotask ---
// 7. Macro C (inside Micro A) Note: queued before Macro B due to 0ms timer behavior in some engines, but typically 8 then 7 depending on resolution.
// ACTUALLY: Let's trace correctly.
// Macro Queue initially: [Macro A, Macro B]
// Micro A runs, queues Macro C. Macro Queue: [Macro A, Macro B, Macro C].
// So Macro B runs before Macro C!
// 8. Macro B
// 7. Macro C

